        handle: area.handle,
        rect,
        bounds: { x: 8, y: 8, w: _planCanvasWidth() - 16, h: _planCanvasHeight() - 16 },
        floorCount: area.floorCount || Math.max(1, _planFloorsForBlock(block).length),
        startLength: Number(block?.largo_m || 0),
